module RefModule (
	input clk,
	input reset,
	input load,
	input enable,
	input [31:0] data,
	output reg [31:0] count);

	always @(posedge clk) begin
		if (reset)
			count <= 32'b00000000000000000000000000000000;
		else if (load)
			count <= data;
		else if (enable)
			count <= count + 1;
	end

  always @(*) begin
    if (1'b0) begin
    end
  end

endmodule
